function NetworkManager:GetCurLineAddress()
	--内网直接返回
	if App.IsDebug() or App.IsGPTest() then
		return self:GetGameServerUrl()
	end

	--外网
	local curLineName = self:GetCurLineName()
	for _, v in pairs(LineList) do
		if v.Name == curLineName then
			return v.Address
		end
	end

	return self:GetGameServerUrl()
end

