function NetworkManager:ClearAllLines()
    for _, p in pairs(self.allSelectProxy) do
        p:Disconnect()
    end

    table.clear(self.allSelectProxy)
end

-- 代理的端口转发规则
function NetworkManager:GetPortId(zoneId)
	
	-- 有问题默认进1服
	zoneId = tonumber(zoneId) or 1
	local port = 8101
	if zoneId > 9000 then
		port = 10500 + zoneId - 9000
	else
		port = 8100 + zoneId
	end
		
	return port

end


-- 获取所有线路
function NetworkManager:GetProxyLines()
	local list = {}
	
	---- 首先加入
	--local oneData = {}
	--oneData.lineName = "direct"
	--oneData.lineUrl = self:GetGameServerUrl()
	--oneData.port = self:GetGameServerPort()
	--table.insert(list, oneData)
	
	-- 然后加入转发的proxy的代理服务器列表
	--zlh: release或者内网连外网服务器走多条线
	local isPublicHostUrl = App.IsEditorConnectedToRelease()
	if (not App.IsDebug() and (not App.IsGPTest())) or isPublicHostUrl  then
		local serverId = CommonUtil.GetServerId()
		if serverId > 0 then
			-- 端口规则：8100+服务器id
			local port = self:GetPortId(serverId)
			for _, v in pairs(LineList) do
				local oneData = {}
				oneData.lineName = v.Name
				oneData.lineUrl = v.Address
				oneData.port = port
				table.insert(list, oneData)					
			end
		end
	end
	
	return list
end

-- NetProxy 是指SmartFox
-- NetRawProxy 是指原始socket实现的网络接口
function NetworkManager:InitLine()
	NetPrint("NetworkManager:InitLine")
	
	table.clear(self.allSelectProxy)
	
    local proxyCfgList = self:GetProxyLines()
    local hasLine = false

    for _, data in pairs(proxyCfgList) do
        local lineName = tostring(data['lineName'])
        local lineUrl = tostring(data['lineUrl'])
        local port = tonumber(data['port'])

        if lineName ~= nil and lineUrl ~= nil and port ~= nil then
            local line = NetProxy(lineName, lineUrl, port, self.cSharpNetwork)
            --local line = NetRawProxy(lineName, lineUrl, port, self.cSharpNetwork)

            table.insert(self.allSelectProxy, line)
            hasLine = true
			
			NetPrint("insert proxy line - %s:%d", lineName, port)
        end
    end


	-- 如果没有转发的话 ，就直接使用直连
    if not hasLine then
        local serverUrl = self.GameServerUrl
        local serverPort = self.GameServerPort
		NetPrint("insert direct line - %s:%d", serverUrl, serverPort)
        
        local direct = NetProxy("direct", self.GameServerUrl, self.GameServerPort, self.cSharpNetwork)
        --local direct = NetRawProxy("direct", self.GameServerUrl, self.GameServerPort, self.cSharpNetwork)
        table.insert(self.allSelectProxy, direct)
		hasLine = true
    end
	
	if hasLine == false then
		Logger.LogError("no line!!")
	end
	
end

function NetworkManager:ChooseOneLine()
    self:InitLine()
    for _, p in pairs(self.allSelectProxy) do
        p:Connect()
    end
end

