-- 设置当前的proxy
function NetworkManager:SetCurProxy(proxy)
	
	self.curProxy = proxy
	if self.cSharpNetwork then
		self.cSharpNetwork:SetCurProxy(proxy)
	else
		-- 这里永远不可能走到
		NetPrint("set cur proxy error")
	end
end

function NetworkManager:OnConnection(proxy) 
	NetPrint("OnConnection! proxy: " .. tostring(proxy and proxy.proxyName))
	
	-- 如果当前已经有连接到的proxy了，那么就放弃
    local curProxy = self:GetCurLineProxy()
	if curProxy ~= nil then
		NetPrint("OnConnection - already has proxy!")
		return false
	end
	
    for _, p in pairs(self.allSelectProxy) do
        if p.proxyName ~= proxy.proxyName then
            p:Disconnect()
        end
    end
    
	self:SetCurProxy(proxy)
    table.clear(self.allSelectProxy)
	self.isConnecting = false
	NetPrint("OnConnection - cur proxy = " .. proxy.proxyName)
    
    --消息推送相关
    local pushType = Setting:GetPrivateString(SettingKeys.GAME_ACCOUNT, "")
    if not string.IsNullOrEmpty(pushType) then
        Setting:SetPrivateString('CATCH_PUSH_TYPE', "")
    end

    --if self.onConnectionEvent then
        --self.onConnectionEvent(Const.LoginErrorCode.ERROR_SUCCESS)
    --end

	--编辑器连线上服自动处理下
	if App.IsEditor() then
		local t = App.IsEditorConnectedToRelease()
		Setting:SetPublicInt('Editor_ConnectOnline', t and 1 or 0)
	end
	
	EventManager:GetInstance():Broadcast(EventId.GameOnConnectOK, Const.LoginErrorCode.ERROR_SUCCESS)

    return true
end

-- 某一条代理连接错误
function NetworkManager:OnConnectionError(proxy, error, errorMessage)
	error = tostring(error)
	NetPrint("NetworkManager:OnConnectionError: " .. error)

	-- 连接的时候会有多个connect并发连接
	local allError = true
	if self:GetCurLineProxy() ~= nil then
		allError = true
	else
		-- 判断是否所有的proxy都已经连接错误了
		for _, p in pairs(self.allSelectProxy) do
			if p.Status ~= ProxyStatus.connectError then
				allError = false
				break
			end
		end
	end

	if allError then
		NetPrint("OnConnectionError - allerror")
		self:Disconnect()
		-- 停服公告
		-- 在每一次重连的时候,先去判定一下是否已经停服
		if AppStartupLoading:GetInstance():CheckServerStateStop() then
			EventManager:GetInstance():Broadcast(EventId.Net_Connect_Error, Const.LoginErrorCode.ERROR_MAINTENANCE)
			return
		end
		
		if self.onConnectionEvent ~= nil then
			if errorMessage ~= nil and string.contains(errorMessage, 'Network is unreachable') then
				self.onConnectionEvent(Const.LoginErrorCode.ERROR_UNREACHABLE, "OnConnectionError")
			else
				self.onConnectionEvent(Const.LoginErrorCode.ERROR_NETWORK, "OnConnectionError")
			end
		end

		local errCode = tonumber(error) or 0
		if error == Const.LoginErrorCode.ERROR_NO_NET or 
			error == Const.LoginErrorCode.ERROR_CONN_LOST or
			errCode < -200 then
			
			EventManager:GetInstance():Broadcast(EventId.Net_Connect_Error, error)
			return
		end

		EventManager:GetInstance():Broadcast(EventId.Net_Connect_Error, Const.LoginErrorCode.ERROR_CONNECT)
	end
end

function NetworkManager:OnConnectionLost(reason, proxy)
	NetPrint("OnConnectionLost")

	-- 在每一次重连的时候,先去判定一下是否已经停服
	if AppStartupLoading:GetInstance():CheckServerStateStop() then
		self:Disconnect()
		EventManager:GetInstance():Broadcast(EventId.Net_Connect_Error, Const.LoginErrorCode.ERROR_MAINTENANCE)
		return
	end
	
	-- 在连接状态的话，可能要处理其他线的情况
	if self:IsConnecting() then
		Logger.Log('OnConnectionLost - IsConnecting - line ', proxy.proxyName)
		--self:OnConnectionError(proxy, Const.LoginErrorCode.ERROR_CONN_LOST, '')
		return
	end
	
    local curLineName = self:GetCurLineName()
    Logger.LogFormat('Connection %s was lost, Reason:%s cur line %s', proxy.proxyName, reason, curLineName)
	
    local curProxy = self:GetCurLineProxy()
    if curProxy ~= nil and curProxy.proxyName ~= proxy.proxyName then
        Logger.LogFormat('line %s lost not cur %s line do nothing', proxy.proxyName, curLineName)
        return
    end

    if LuaEntry.GlobalData:IsInBackground() then
		NetPrint("connection lost but in background!")
		self:Disconnect()
        return
    end
 
    --被其他手机给顶了就不连了
    if LuaEntry.GlobalData.pushOffWithQuitGame then
		NetPrint("connection lost --- pushOffWithQuitGame!")
        self:Disconnect()
        return
    end
    ---- 在这块请求服务器状态
    --AppStartupLoading:GetInstance():RequestServerStateUrl()
	self:Disconnect()
    if not AppStartupLoading:GetInstance():CheckServerStateStop() then -- 如果停服的情况下,没有必要继续连接
        self:Reconnect('connection lost, reason:' .. reason)
    end
end

function NetworkManager:OnLogin(message)
	NetPrint("NetworkManager:OnLogin")
	
	-- 如果message为nil的话，就是未知错误！
	if message == nil then
		self:OnLoginError(0, "InternalError")
		return
	end
    
	AppStartupLoading:GetInstance():OnLogin(message)
end

