function NetworkManager:Update()
    local now = Time.time
    if now - self.lastUpdateTime > 3 then
        self.lastUpdateTime = now
        self:CheckOffline()
    end
    
    if self.curProxy ~= nil then
        self.curProxy:UpdateSmartFoxClient()
    else
        for _, proxy in pairs(self.allSelectProxy) do
            proxy:UpdateSmartFoxClient()
        end
    end
end

function NetworkManager:OnConnectionEvent(callback)
    self.onConnectionEvent = callback
end

function NetworkManager:Connect()
	NetPrint("NetworkManager:Connect begin")
	
    if App.IsEditor() then
        self:OnBeforeConnect()
    end

	-- 重连时清除配置缓存
	CS.GameEntry.ConfigCache:reset()
	
    --清理所有正在连接中的线路
    self:ClearAllLines()
    self:ChooseOneLine()
    local futureManager = self:GetFutureManager()
    if futureManager then
        futureManager:reset()
    end
	self.isConnecting = true
	
	NetPrint("NetworkManager:do Connect ok")
end

function NetworkManager:Disconnect()
	NetPrint("NetworkManager:do Disconnect")
    
    if self.curProxy ~= nil then
        self.curProxy:Disconnect()
        --self.curProxy = nil
		self:SetCurProxy(nil)
    end
	
	self:ClearAllLines()
	
	self.isConnecting = false
end


-- 这个地方其实写的不是很好
-- 1. reconnect 其实是弹出DisconnectView 这个UI，并不是真正的Reconnect。会在UI中判断
-- 2. 这个函数的职责不应该存在于Network中，而是LuaEntry中处理
function NetworkManager:Reconnect(recordStr)
    --CS.PostEventLog.Record(CS.PostEventLog.Defines.DISCONNECT_RETRY, recordStr or '')
	NetPrint('NetworkManager:Reconnect')

	if AppStartupLoading:GetInstance():IsLoading() then
		--NetPrint("CheckOffline - IsLoading")
		return
	end
    
	-- 已经处于重连窗口状态了，不重复处理；
    if UIManager:GetInstance():IsWindowOpen(UIWindowNames.UIDisconnect) then
		Logger.Log("UIDisconnect alreay open! Reconnect - ", recordStr)
        return
    end
	
	--躲避球里不关闭UI了，
	if DataCenter.LWBattleManager:IsInBattle() or SceneManager.IsArena() then
		
	else
		-- 只需要关闭普通窗口和引导层
		-- 普通窗口：因为很多时候普通窗口只是在开启的时候同步了一下服务器信息，譬如活动等
		--          如果不关闭的话，可能会有很多不同步的情况。场景信息必须同步，否则是BUG
		-- 引导层：这个要关闭，因为普通窗口关闭了，如果引导层不关闭，会留下箭头。
		UIManager:GetInstance():DestroyWindowByLayer(UILayer.Guide)
		UIManager:GetInstance():DestroyWindowByLayer(UILayer.Normal)
		UIManager:GetInstance():DestroyWindowByLayer(UILayer.Scene)
	end
	
	Logger.Log("UIDisconnect open! Reconnect - ", recordStr)
    UIManager:GetInstance():OpenWindow(UIWindowNames.UIDisconnect)
end

function NetworkManager:CheckOffline()
    if LuaEntry.GlobalData.pushOffWithQuitGame then
		NetPrint("CheckOffline - pushOffWithQuitGame")
        return
    end

    if AppStartupLoading:GetInstance():IsLoading() then
		--NetPrint("CheckOffline - IsLoading")
        return
    end

	if self:IsConnecting() then
		if App.IsDebug() or App.IsGPTest() then
			NetPrint("CheckOffline - IsConnecting")
		end
		return
	end
    
	-- 只有连接情况才进行pingpong检测；否则网络断开后pingping永远是超时啊
	if self:IsConnected() then 
		if App.IsEditor() then
			-- 如果在editor模式下，不去处理pingpong，防止调试被卡
		else
		    if self:IsPingPongTimeOut() then
				PostEventLog.Record("PingPongTimeOut")
		        self:Reconnect('PingPongTimeOut')
		    end
		end
	else
		PostEventLog.Record("CheckOffline - Not Connected!?")
	end
end


function NetworkManager:SendLuaMessage(msgId, sfsObjBinary)
    self.cSharpNetwork:SendLuaMessage(msgId, sfsObjBinary)
end

function NetworkManager:SendLuaMessageEx(msgId, sfsObj)
    local futureId = self.futureManger:getFutureId()
    self.futureManger:onSendRequest(futureId, _ToID(msgId))
    sfsObj:PutInt("_id", futureId)

    if App.IsEditor() then
        if msgId ~= 'survival.pve.heartbeat' then
			local t = sfsObj:ToLuaTable()
            --local rapidjson = require "rapidjson"
            --local jsonStr = rapidjson.encode(sfsObj)
			local rapidjson = require "rapidjson"
			local jsonStr = rapidjson.encode(t)

            Logger.Log(string.format("<color=cyan>#message# [req] <%s> |</color> {%s}", msgId, jsonStr))
        end
    end
    
    self.cSharpNetwork:SendLuaMessageEx(msgId, sfsObj)
end

function NetworkManager:SimulateKill()
	if self.curProxy ~= nil then
		self.curProxy:KillConnection()
	end
end

return NetworkManager